const botUrl = 'https://t.me/topposter69_bot';
const robot = document.getElementById('heroRobot');
const ctaRobot = document.getElementById('ctaRobot');
const currentLang = document.getElementById('currentLang');
const toggle = document.getElementById('langToggle');

function setLanguage(lang){
  const pack = dict[lang] || dict.ru;

  document.documentElement.lang = lang;
  document.documentElement.dataset.lang = lang;
  currentLang.textContent = lang.toUpperCase();

  document.querySelectorAll('[data-i18n], [data-i18n-html]').forEach(el => {
    const key = el.dataset.i18n || el.dataset.i18nHtml;
    const value = pack[key];

    if (!value) return;

    // 🔥 если есть HTML — вставляем как HTML
    if (value.includes('<')) {
      el.innerHTML = value;
    } else {
      el.textContent = value;
    }
  });

  const heroSrc = lang === 'en'
    ? 'assets/hero-scene-en.png'
    : 'assets/hero-scene-ru.png';

  const ctaSrc = lang === 'en'
    ? 'assets/hero-robot-en.png'
    : 'assets/hero-robot-ru.png';

  if (robot) robot.src = heroSrc;
  if (ctaRobot) ctaRobot.src = ctaSrc;

  const openBotLinks = [document.getElementById('header-open-bot'), document.getElementById('cta-open-bot')];
  openBotLinks.forEach(link => {
    if (link) link.href = botUrl;
  });

  localStorage.setItem('vimi_lang', lang);
}

toggle.addEventListener('click', () => {
  const next = (localStorage.getItem('vimi_lang') || 'ru') === 'ru' ? 'en' : 'ru';
  setLanguage(next);
});

setLanguage(localStorage.getItem('vimi_lang') || 'ru');
